/**
 * backend/src/middleware/admin-audit.ts
 * 
 * Admin action audit logging middleware
 * Logs all write operations in the Orange layer for security auditing
 */

import { Context, Next } from 'hono';
import { getEnv, getClientIp, safeJsonStringify } from '@cp/config';

// ============================================
// AUDIT LOG TYPES
// ============================================

export interface AuditLogEntry {
    timestamp: string;
    action: string;
    method: string;
    path: string;
    ip: string;
    userAgent: string;
    adminId?: number;
    adminUsername?: string;
    statusCode?: number;
    durationMs?: number;
    requestBody?: string;
    error?: string;
}

// In-memory buffer for batch writing (optional - can be extended to write to DB)
const auditBuffer: AuditLogEntry[] = [];
const MAX_BUFFER_SIZE = 100;

// ============================================
// AUDIT FUNCTIONS
// ============================================

/**
 * Log an admin action
 */
export function logAdminAction(entry: AuditLogEntry): void {
    // Add to buffer
    auditBuffer.push(entry);

    // Also log to console with structured format
    console.log(`[ADMIN AUDIT] ${entry.timestamp} | ${entry.method} ${entry.path} | IP: ${entry.ip} | Status: ${entry.statusCode || 'pending'}`);

    // Trim buffer if too large
    if (auditBuffer.length > MAX_BUFFER_SIZE) {
        auditBuffer.shift();
    }
}

/**
 * Get recent audit logs
 */
export function getRecentAuditLogs(limit: number = 50): AuditLogEntry[] {
    return auditBuffer.slice(-limit).reverse();
}

/**
 * Clear audit buffer
 */
export function clearAuditBuffer(): void {
    auditBuffer.length = 0;
}

// ============================================
// MIDDLEWARE
// ============================================

/**
 * Admin audit logging middleware
 * Should be applied to Orange layer routes
 */
export const adminAuditMiddleware = async (c: Context, next: Next) => {
    // Only audit write operations
    const method = c.req.method;
    if (method === 'GET' || method === 'OPTIONS' || method === 'HEAD') {
        return next();
    }

    const startTime = Date.now();
    const timestamp = new Date().toISOString();
    const ip = getClientIp(c.req.raw.headers as unknown as { get(name: string): string | undefined });
    const userAgent = c.req.header('User-Agent') || 'unknown';
    const path = c.req.path;

    // Try to get request body for logging (clone the request)
    let requestBodyStr: string | undefined;
    try {
        const body = await c.req.json();
        // Sanitize sensitive fields before logging
        const sanitizedBody = { ...body };
        if (sanitizedBody.password) sanitizedBody.password = '[REDACTED]';
        if (sanitizedBody.currentPassword) sanitizedBody.currentPassword = '[REDACTED]';
        if (sanitizedBody.newPassword) sanitizedBody.newPassword = '[REDACTED]';
        if (sanitizedBody.passwordHash) sanitizedBody.passwordHash = '[REDACTED]';
        requestBodyStr = safeJsonStringify(sanitizedBody, '{}');
    } catch {
        // No JSON body or already consumed
    }

    // Get admin info from context if available
    const adminUser = (c as any).adminUser;

    let statusCode: number | undefined;
    let errorMsg: string | undefined;

    try {
        await next();
        statusCode = c.res.status;
    } catch (err) {
        errorMsg = err instanceof Error ? err.message : String(err);
        statusCode = 500;
        throw err;
    } finally {
        const durationMs = Date.now() - startTime;

        logAdminAction({
            timestamp,
            action: `${method} ${path}`,
            method,
            path,
            ip,
            userAgent,
            adminId: adminUser?.id,
            adminUsername: adminUser?.username,
            statusCode,
            durationMs,
            requestBody: requestBodyStr,
            error: errorMsg,
        });
    }
};

/**
 * Get audit logs handler (can be exposed as an endpoint)
 */
export function getAuditLogs(c: Context) {
    const limit = parseInt(c.req.query('limit') || '50', 10);
    const logs = getRecentAuditLogs(Math.min(limit, 100));

    return c.json({
        status: 'success',
        data: logs,
        total: logs.length,
    });
}

import { Context, Next } from 'hono';
import { createDb, apiKeys, apiLogs, eq } from '@modular/database';
import {
    getEnv,
    unauthorized,
    forbidden,
    serverError,
    systemNotReady,
} from '@cp/config';

/**
 * API GUARD MIDDLEWARE
 * Validates 'x-api-key' header and logs request performance/status.
 */
export const apiGuard = async (c: Context, next: Next) => {
    const env = getEnv(c);
    if (!env.DATABASE_URL) return systemNotReady(c);

    const apiKey = c.req.header('x-api-key');
    if (!apiKey) return unauthorized(c, 'Missing API Key');

    const start = Date.now();
    const db = createDb(env.DATABASE_URL);

    try {
        const [keyData] = await db.select()
            .from(apiKeys)
            .where(eq(apiKeys.key, apiKey))
            .limit(1);

        if (!keyData || !keyData.isActive) {
            return forbidden(c, 'Invalid or Inactive API Key');
        }

        // Update last used timestamp (Async, don't block request)
        db.update(apiKeys).set({ lastUsedAt: new Date() }).where(eq(apiKeys.id, keyData.id)).execute();

        // Store key data for downstream usage (RBAC)
        c.set('keyData', keyData);

        // Continue to actual logic
        await next();

        // Log the request
        const duration = Date.now() - start;
        await db.insert(apiLogs).values({
            apiKeyId: keyData.id,
            endpoint: c.req.path,
            method: c.req.method,
            statusCode: c.res.status,
            durationMs: duration,
            origin: c.req.header('Origin') || null,
            ip: c.req.header('x-forwarded-for') || '127.0.0.1',
            userAgent: c.req.header('User-Agent') || null
        });

    } catch (error: any) {
        console.error('API Guard Error:', error);
        return serverError(c, 'Security processing error');
    }
};

/**
 * CSRF Protection Middleware
 * Implements Double-Submit Cookie pattern for CSRF protection
 */

import { Context, Next } from 'hono';
import { getCookie, setCookie } from 'hono/cookie';
import { getEnv, unauthorized, badRequest, isDev } from '@cp/config';
import crypto from 'crypto';

// CSRF token cookie name
const CSRF_TOKEN_COOKIE = 'csrf-token';
const CSRF_TOKEN_HEADER = 'x-csrf-token';

// Methods that require CSRF protection
const PROTECTED_METHODS = ['POST', 'PUT', 'DELETE', 'PATCH'];

/**
 * Generate a random CSRF token
 */
function generateToken(): string {
    return crypto.randomBytes(32).toString('hex');
}

/**
 * Validate CSRF token
 * Uses Double-Submit Cookie pattern:
 * - Token stored in httpOnly cookie
 * - Same token sent in header
 * - Both must match
 */
export const csrfProtection = async (c: Context, next: Next) => {
    const method = c.req.method;

    // Skip CSRF check for safe methods
    if (!PROTECTED_METHODS.includes(method)) {
        return next();
    }

    // Skip CSRF check for health/status endpoints
    if (c.req.path.endsWith('/health') || c.req.path.endsWith('/status')) {
        return next();
    }

    const env = getEnv(c);
    const isProduction = !isDev();

    // Get token from cookie
    const cookieToken = getCookie(c, CSRF_TOKEN_COOKIE);

    // Get token from header
    const headerToken = c.req.header(CSRF_TOKEN_HEADER);

    // Validate tokens match
    if (!cookieToken || !headerToken) {
        if (isProduction) {
            return unauthorized(c, 'CSRF token missing');
        }
        // In development, generate and set token if missing
        if (!cookieToken) {
            const newToken = generateToken();
            setCookie(c, CSRF_TOKEN_COOKIE, newToken, {
                httpOnly: true,
                secure: isProduction,
                sameSite: 'strict',
                maxAge: 60 * 60 * 24, // 24 hours
                path: '/'
            });
            // Allow first request in dev mode
            return next();
        }
        return unauthorized(c, 'CSRF token missing');
    }

    // Validate tokens match (constant-time comparison)
    if (cookieToken !== headerToken) {
        return unauthorized(c, 'CSRF token mismatch');
    }

    return next();
};

/**
 * Middleware to set CSRF token cookie
 * Should be applied to all routes to ensure token is available
 */
export const csrfToken = async (c: Context, next: Next) => {
    const env = getEnv(c);
    const isProduction = !isDev();

    // Check if token already exists
    const existingToken = getCookie(c, CSRF_TOKEN_COOKIE);

    if (!existingToken) {
        // Generate and set new token
        const token = generateToken();
        setCookie(c, CSRF_TOKEN_COOKIE, token, {
            httpOnly: true,
            secure: isProduction,
            sameSite: 'strict',
            maxAge: 60 * 60 * 24, // 24 hours
            path: '/'
        });
    }

    // Add token to response header for frontend to read (if needed)
    // Note: Frontend should read from cookie via API endpoint instead
    await next();
};

/**
 * Get CSRF token endpoint
 * Returns the CSRF token for frontend to use in requests
 * Token is also available in cookie
 */
export const getCsrfToken = (c: Context) => {
    const token = getCookie(c, CSRF_TOKEN_COOKIE);

    if (!token) {
        // Generate new token
        const newToken = generateToken();
        const isProduction = !isDev();

        setCookie(c, CSRF_TOKEN_COOKIE, newToken, {
            httpOnly: true,
            secure: isProduction,
            sameSite: 'strict',
            maxAge: 60 * 60 * 24, // 24 hours
            path: '/'
        });

        return c.json({
            status: 'success',
            token: newToken
        });
    }

    return c.json({
        status: 'success',
        token: token
    });
};

import { Context, Next } from 'hono';
import { cors } from 'hono/cors';
import { createDb, corsDomains, sql } from '@modular/database';
import {
    getEnv,
    CORS_METHODS,
    ALLOWED_HEADERS,
    CORS,
    SECURITY_LIMITS,
    isProd,
} from '@cp/config';

// ============================================
// CORS CACHE
// ============================================

interface CacheEntry {
    allowed: boolean;
    expires: number;
}

// In-memory cache for CORS domains
const corsCache = new Map<string, CacheEntry>();

/**
 * Check if origin is cached
 */
function getCachedOrigin(origin: string): boolean | null {
    const entry = corsCache.get(origin);
    if (!entry) return null;

    // Check if expired
    if (Date.now() > entry.expires) {
        corsCache.delete(origin);
        return null;
    }

    return entry.allowed;
}

/**
 * Cache an origin result
 */
function cacheOrigin(origin: string, allowed: boolean): void {
    corsCache.set(origin, {
        allowed,
        expires: Date.now() + SECURITY_LIMITS.CORS_CACHE_TTL_MS,
    });
}

/**
 * Clear the CORS cache (can be called when domains are updated)
 */
export function clearCorsCache(): void {
    corsCache.clear();
}

// ============================================
// DYNAMIC CORS MIDDLEWARE
// ============================================

/**
 * DYNAMIC CORS MIDDLEWARE
 * Fetches allowed origins from the database for secure cross-origin requests.
 * Results are cached to avoid database query on every request.
 */
export const dynamicCors = async (c: Context, next: Next) => {
    const env = getEnv(c);
    if (!env.DATABASE_URL) return next();

    try {
        const origin = c.req.header('Origin');
        if (!origin) return next();

        // Check cache first
        const cachedResult = getCachedOrigin(origin);
        if (cachedResult !== null) {
            if (cachedResult) {
                const corsMiddleware = cors({
                    origin: origin,
                    allowMethods: [...CORS_METHODS],
                    allowHeaders: [...ALLOWED_HEADERS],
                    credentials: CORS.CREDENTIALS,
                });
                return corsMiddleware(c, next);
            }
            // Not allowed, continue without CORS headers
            return next();
        }

        // Query database
        const db = createDb(env.DATABASE_URL);

        // In production, explicitly reject wildcard CORS
        if (isProd()) {
            // Only allow specific domains in production
            const [domain] = await db.select()
                .from(corsDomains)
                .where(sql`${corsDomains.domain} = ${origin} AND ${corsDomains.domain} != '*' AND ${corsDomains.isActive} = 1`)
                .limit(1);

            const isAllowed = !!domain;
            cacheOrigin(origin, isAllowed);

            if (isAllowed) {
                const corsMiddleware = cors({
                    origin: origin,
                    allowMethods: [...CORS_METHODS],
                    allowHeaders: [...ALLOWED_HEADERS],
                    credentials: CORS.CREDENTIALS,
                });
                return corsMiddleware(c, next);
            } else {
                // Log security event for rejected CORS in production
                console.warn(`[SECURITY] CORS request rejected for origin: ${origin} (not in whitelist)`);
                return next(); // Continue without CORS headers
            }
        } else {
            // Development: Allow wildcard but warn
            const [domain] = await db.select()
                .from(corsDomains)
                .where(sql`(${corsDomains.domain} = ${origin} OR ${corsDomains.domain} = '*') AND ${corsDomains.isActive} = 1`)
                .limit(1);

            const isAllowed = !!domain;

            // Warn about wildcard CORS in development
            if (domain?.domain === '*') {
                console.warn('[SECURITY WARNING] Wildcard CORS (*) is enabled. This will be disabled in production.');
            }

            cacheOrigin(origin, isAllowed);

            if (isAllowed) {
                const corsMiddleware = cors({
                    origin: origin,
                    allowMethods: [...CORS_METHODS],
                    allowHeaders: [...ALLOWED_HEADERS],
                    credentials: CORS.CREDENTIALS,
                });
                return corsMiddleware(c, next);
            }
        }
    } catch (error) {
        console.error('[CORS] Database error:', error);
        // On error, don't cache and continue without CORS
    }

    return next();
};

/**
 * backend/src/middleware/rate-limiter.ts
 * 
 * Rate limiting middleware for Hono
 * Uses in-memory store with sliding window algorithm
 */

import { Context, Next } from 'hono';
import { RATE_LIMITS, getClientIp, logSecurityEvent } from '@cp/config';

// ============================================
// RATE LIMITER STORE
// ============================================

interface RateLimitEntry {
    count: number;
    resetAt: number;
}

// In-memory store for rate limit tracking
const rateLimitStore = new Map<string, RateLimitEntry>();

// Clean up expired entries every minute
setInterval(() => {
    const now = Date.now();
    for (const [key, entry] of rateLimitStore.entries()) {
        if (entry.resetAt < now) {
            rateLimitStore.delete(key);
        }
    }
}, 60 * 1000);

// ============================================
// RATE LIMITER FUNCTIONS
// ============================================

/**
 * Check if request is rate limited
 */
function isRateLimited(
    key: string,
    maxRequests: number,
    windowMs: number
): { limited: boolean; remaining: number; resetAt: number } {
    const now = Date.now();
    const entry = rateLimitStore.get(key);

    // No entry or expired - create new
    if (!entry || entry.resetAt < now) {
        const resetAt = now + windowMs;
        rateLimitStore.set(key, { count: 1, resetAt });
        return { limited: false, remaining: maxRequests - 1, resetAt };
    }

    // Increment count
    entry.count++;

    if (entry.count > maxRequests) {
        return { limited: true, remaining: 0, resetAt: entry.resetAt };
    }

    return { limited: false, remaining: maxRequests - entry.count, resetAt: entry.resetAt };
}

// ============================================
// MIDDLEWARE FACTORIES
// ============================================

/**
 * Create a rate limiter middleware with custom options
 */
export function createRateLimiter(options: {
    windowMs: number;
    maxRequests: number;
    keyPrefix?: string;
    message?: string;
}) {
    const { windowMs, maxRequests, keyPrefix = 'rl', message = 'Too many requests' } = options;

    return async (c: Context, next: Next) => {
        const ip = getClientIp(c.req.raw.headers as unknown as { get(name: string): string | undefined });
        const key = `${keyPrefix}:${ip}`;

        const { limited, remaining, resetAt } = isRateLimited(key, maxRequests, windowMs);

        // Set rate limit headers
        c.header('X-RateLimit-Limit', String(maxRequests));
        c.header('X-RateLimit-Remaining', String(remaining));
        c.header('X-RateLimit-Reset', String(Math.ceil(resetAt / 1000)));

        if (limited) {
            logSecurityEvent('RATE_LIMIT_EXCEEDED', { ip, key, maxRequests });

            return c.json({
                status: 'error',
                code: 429,
                message,
                retryAfter: Math.ceil((resetAt - Date.now()) / 1000),
            }, 429);
        }

        return next();
    };
}

// ============================================
// PRE-CONFIGURED RATE LIMITERS
// ============================================

/**
 * Global rate limiter for all API requests
 * Default: 100 requests per minute per IP
 */
export const globalRateLimiter = createRateLimiter({
    windowMs: RATE_LIMITS.GLOBAL.WINDOW_MS,
    maxRequests: RATE_LIMITS.GLOBAL.REQUESTS_PER_MINUTE,
    keyPrefix: 'global',
    message: 'Too many requests. Please try again later.',
});

/**
 * Stricter rate limiter for mutation (write) operations
 * Default: 30 requests per minute per IP
 */
export const mutationRateLimiter = createRateLimiter({
    windowMs: RATE_LIMITS.MUTATION.WINDOW_MS,
    maxRequests: RATE_LIMITS.MUTATION.REQUESTS_PER_MINUTE,
    keyPrefix: 'mutation',
    message: 'Too many write operations. Please slow down.',
});

/**
 * Very strict rate limiter for registration
 * Default: 5 registrations per hour per IP
 */
export const registrationRateLimiter = createRateLimiter({
    windowMs: RATE_LIMITS.REGISTER.WINDOW_MS,
    maxRequests: RATE_LIMITS.REGISTER.REQUESTS_PER_HOUR,
    keyPrefix: 'register',
    message: 'Registration limit exceeded. Please try again later.',
});

/**
 * Admin login rate limiter (stricter)
 * 10 attempts per 15 minutes per IP
 */
export const adminLoginRateLimiter = createRateLimiter({
    windowMs: 15 * 60 * 1000,
    maxRequests: 10,
    keyPrefix: 'admin-login',
    message: 'Too many login attempts. Please try again in 15 minutes.',
});

import { Context, Next } from 'hono';
import { createDb, apiLogs } from '@modular/database';
import { getEnv } from '@cp/config';

/**
 * REQUEST LOGGER MIDDLEWARE
 * Logs ALL API requests to database for monitoring dashboard.
 * This is separate from apiGuard to log requests that don't require API keys.
 */
export const requestLogger = async (c: Context, next: Next) => {
    const env = getEnv(c);
    if (!env.DATABASE_URL) {
        // No database, just continue without logging
        return next();
    }

    const start = Date.now();

    try {
        // Continue to actual logic first
        await next();

        // Log the request after response
        const duration = Date.now() - start;
        const db = createDb(env.DATABASE_URL);

        // Fire and forget - don't block response
        db.insert(apiLogs).values({
            apiKeyId: null, // No API key for general requests
            endpoint: c.req.path,
            method: c.req.method,
            statusCode: c.res.status,
            durationMs: duration,
            origin: c.req.header('Origin') || null,
            ip: c.req.header('x-forwarded-for') || c.req.header('x-real-ip') || '127.0.0.1',
            userAgent: c.req.header('User-Agent') || null
        }).execute().catch(err => {
            // Silent fail - don't crash the app for logging failures
            console.error('Request logging failed:', err.message);
        });

    } catch (error) {
        // If the main handler threw an error, still try to log it
        const duration = Date.now() - start;
        try {
            const db = createDb(env.DATABASE_URL);
            await db.insert(apiLogs).values({
                apiKeyId: null,
                endpoint: c.req.path,
                method: c.req.method,
                statusCode: 500,
                durationMs: duration,
                origin: c.req.header('Origin') || null,
                ip: c.req.header('x-forwarded-for') || '127.0.0.1',
                userAgent: c.req.header('User-Agent') || null
            });
        } catch {
            // Ignore logging errors
        }
        throw error; // Re-throw to let error handlers deal with it
    }
};

