import { Context, Next } from 'hono';
import * as jwt from 'jsonwebtoken';
import {
    getEnv,
    unauthorized,
    forbidden,
    MSG,
    ERROR,
    isSuperRole,
} from '@cp/config';

/**
 * USER AUTH MIDDLEWARE (For Green Layer)
 * Validates JWT Bearer token and extracts user info for RBAC
 */
export const userAuth = async (c: Context, next: Next) => {
    const authHeader = c.req.header('Authorization');

    if (!authHeader || !authHeader.startsWith('Bearer ')) {
        return unauthorized(c, 'Missing or invalid Authorization header');
    }

    const token = authHeader.substring(7); // Remove 'Bearer ' prefix
    const env = getEnv(c);

    try {
        const decoded = jwt.verify(token, env.JWT_SECRET) as {
            id: number;
            username: string;
            email: string;
            role: string;
            permissions: string[];
        };

        // Attach user info to context for downstream use
        c.set('user', {
            id: decoded.id,
            username: decoded.username,
            email: decoded.email,
            role: decoded.role,
            permissions: decoded.permissions || []
        });

        await next();
    } catch (error: any) {
        if (error.name === 'TokenExpiredError') {
            return unauthorized(c, ERROR.TOKEN_EXPIRED);
        }
        return unauthorized(c, ERROR.TOKEN_INVALID);
    }
};

/**
 * RBAC CHECK MIDDLEWARE
 * Checks if user has required roles or permissions for an endpoint
 * 
 * @param requiredRoles - Comma-separated roles (OR logic - user needs at least one)
 * @param requiredPermissions - Comma-separated permissions (AND logic - user needs all)
 */
export const checkRBAC = (requiredRoles: string, requiredPermissions: string) => {
    return async (c: Context, next: Next) => {
        const user = c.get('user') as {
            id: number;
            role: string;
            permissions: string[];
        };

        if (!user) {
            return unauthorized(c, 'User not authenticated');
        }

        // super_admin bypasses all RBAC checks (using centralized helper)
        if (isSuperRole(user.role)) {
            await next();
            return;
        }

        // Check roles (OR logic)
        if (requiredRoles) {
            const roles = requiredRoles.split(',').map(r => r.trim()).filter(Boolean);
            if (roles.length > 0 && !roles.includes(user.role)) {
                return forbidden(c, 'Forbidden: Insufficient role');
            }
        }

        // Check permissions (AND logic)
        if (requiredPermissions) {
            const perms = requiredPermissions.split(',').map(p => p.trim()).filter(Boolean);
            const userPerms = user.permissions || [];
            const hasAllPerms = perms.every(p => userPerms.includes(p));

            if (perms.length > 0 && !hasAllPerms) {
                return forbidden(c, 'Forbidden: Missing required permissions');
            }
        }

        await next();
    };
};

/**
 * REQUIRE SUPER ADMIN MIDDLEWARE
 * Restricts access to super admin only (isSuper role)
 */
export const requireSuperAdmin = async (c: Context, next: Next) => {
    const authHeader = c.req.header('Authorization');

    if (!authHeader || !authHeader.startsWith('Bearer ')) {
        return unauthorized(c, 'Missing or invalid Authorization header');
    }

    const token = authHeader.substring(7);
    const env = getEnv(c);

    try {
        const decoded = jwt.verify(token, env.JWT_SECRET) as {
            id: number;
            role: string;
        };

        // Check if user has super role
        if (!isSuperRole(decoded.role)) {
            return forbidden(c, 'Access denied: Super admin required');
        }

        // Attach user info to context
        c.set('user', decoded);
        await next();
    } catch (error: any) {
        if (error.name === 'TokenExpiredError') {
            return unauthorized(c, ERROR.TOKEN_EXPIRED);
        }
        return unauthorized(c, ERROR.TOKEN_INVALID);
    }
};

// ============================================
// GRACEFUL AUTH - For Green Layer Public/Protected Routes
// ============================================

/**
 * User context interface with level information
 */
export interface UserContext {
    id: number;
    username?: string;
    email?: string;
    role: string;
    level: number;
    permissions: string[];
    authenticated: boolean;
}

/**
 * GRACEFUL AUTH MIDDLEWARE (For Green Layer)
 * Parses JWT if present but NEVER blocks the request.
 * Sets user context for downstream handlers to check.
 * - No token = guest user (level 0)
 * - Invalid token = guest user (level 0)
 * - Valid token = authenticated user with role level
 */
export const gracefulAuth = async (c: Context, next: Next) => {
    const authHeader = c.req.header('Authorization');
    const env = getEnv(c);

    // Default: guest user (level 0, not authenticated)
    let user: UserContext = {
        id: 0,
        role: 'guest',
        level: 0,
        permissions: [],
        authenticated: false
    };

    if (authHeader?.startsWith('Bearer ') && env.DATABASE_URL) {
        const token = authHeader.substring(7);

        try {
            // Check if token is blacklisted (logged out)
            const crypto = await import('crypto');
            // We need to match the hashing algorithm used in TokenBlacklistService
            const tokenHash = crypto.createHash('sha256').update(token).digest('hex');

            const db = createDb(env.DATABASE_URL);
            const { tokenBlacklist } = await import('@modular/database');
            const { eq } = await import('@modular/database');

            const [blacklisted] = await db.select()
                .from(tokenBlacklist)
                .where(eq(tokenBlacklist.tokenHash, tokenHash))
                .limit(1);

            const isBlacklisted = !!blacklisted;

            if (isBlacklisted) {
                // Token was logged out - treat as guest
                c.set('user', user);
                await next();
                return;
            }

            const decoded = jwt.verify(token, env.JWT_SECRET) as {
                id: number;
                username: string;
                email: string;
                role: string;
                permissions: string[];
            };

            // Get role level from config
            const { getRoleLevel } = await import('@cp/config');
            const level = getRoleLevel(decoded.role);

            user = {
                id: decoded.id,
                username: decoded.username,
                email: decoded.email,
                role: decoded.role,
                level,
                permissions: decoded.permissions || [],
                authenticated: true
            };
        } catch {
            // Invalid/expired token = stay as guest
            // Don't block - let handler decide
        }
    }

    c.set('user', user);
    await next();
};

/**
 * Helper: Check if user is authenticated
 * Use this in handlers that require login
 */
export const isAuthenticated = (c: Context): boolean => {
    const user = c.get('user') as UserContext | undefined;
    return user?.authenticated === true;
};

/**
 * Helper: Check if user meets minimum role level
 * @param minLevel - Minimum required level (0=guest, 10=user, 50=moderator, 90=admin)
 */
export const hasMinLevel = (c: Context, minLevel: number): boolean => {
    const user = c.get('user') as UserContext | undefined;
    return (user?.level ?? 0) >= minLevel;
};

/**
 * Helper: Get user context from request
 */
export const getUser = (c: Context): UserContext => {
    return c.get('user') as UserContext || {
        id: 0,
        role: 'guest',
        level: 0,
        permissions: [],
        authenticated: false
    };
};
